#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <omp.h>

#define RADIUS 7
#define BLOCK_SIZE 256

void stencil_1d(const int *in, int *out, int length) {
  #pragma omp parallel
  {
    int temp[BLOCK_SIZE + 2 * RADIUS];
    int num_blocks = length / BLOCK_SIZE;
    int block_idx = omp_get_thread_num();

    if (block_idx < num_blocks) {
      int gindex_base = block_idx * BLOCK_SIZE;
      int lindex_base = RADIUS;

      // Load main block data
      for (int i = 0; i < BLOCK_SIZE; i++) {
        temp[lindex_base + i] = in[gindex_base + i];
      }

      // Load boundary data (left and right)
      if (block_idx == 0) {
        // Left boundary for first block
        for (int i = 0; i < RADIUS; i++) {
          temp[lindex_base - RADIUS + i] = 0;
        }
      } else {
        // Left boundary from previous block
        for (int i = 0; i < RADIUS; i++) {
          temp[lindex_base - RADIUS + i] = in[gindex_base - RADIUS + i];
        }
      }

      // Right boundary
      if (gindex_base + BLOCK_SIZE < length) {
        for (int i = 0; i < RADIUS; i++) {
          temp[lindex_base + BLOCK_SIZE + i] = in[gindex_base + BLOCK_SIZE + i];
        }
      } else {
        // Handle case where we are at the end (though problem implies length is multiple)
        for (int i = 0; i < RADIUS; i++) {
          if (gindex_base + BLOCK_SIZE + i < length + RADIUS) {
             temp[lindex_base + BLOCK_SIZE + i] = in[gindex_base + BLOCK_SIZE + i];
          } else {
             temp[lindex_base + BLOCK_SIZE + i] = 0; // Or handle appropriately based on original logic
          }
        }
      }

      // Compute stencil for each element in this block
      for (int i = 0; i < BLOCK_SIZE; i++) {
        int gindex = gindex_base + i;
        int lindex = lindex_base + i;
        int result = 0;
        for (int offset = -RADIUS; offset <= RADIUS; offset++) {
          result += temp[lindex + offset];
        }
        out[gindex] = result;
      }
    }
  }
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <length> <repeat>\n", argv[0]);
    printf("length is a multiple of %d\n", BLOCK_SIZE);
    return 1;
  }
  const int length = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  int size = length * sizeof(int);
  int pad_size = (length + RADIUS) * sizeof(int);

  int *a, *b;

  a = (int *)malloc(pad_size); 
  b = (int *)malloc(size);

  for (int i = 0; i < length+RADIUS; i++) a[i] = i;

  // No device memory needed for OpenMP

  dim3 grids (length/BLOCK_SIZE);
  dim3 blocks (BLOCK_SIZE);

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++)
    stencil_1d(a, b, length);

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

  // Verification logic from original code
  bool ok = true;
  for (int i = 0; i < 2*RADIUS; i++) {
    int s = 0;
    for (int j = i; j <= i+2*RADIUS; j++)
      s += j < RADIUS ? 0 : (a[j] - RADIUS);
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }

  for (int i = 2*RADIUS; i < length; i++) {
    int s = 0;
    for (int j = i-RADIUS; j <= i+RADIUS; j++)
      s += a[j];
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(a);
  free(b); 
  return 0;
}

